package main.rice;

import java.util.ArrayList;

/**
 * This class implements a relatively simple algorithm for computing (and printing) the
 * prime factors of a number.  At initialization, a list of primes is computed. Given a
 * number, this list is used to efficiently compute the prime factors of that number.
 */
public class PrimeFactorizer {
    private final int maxNumToFactorize;
    private final int[] primes;

    public PrimeFactorizer(int maxNumToFactorize) {
        this.maxNumToFactorize = maxNumToFactorize;
        this.primes = buildPrimeList(maxNumToFactorize);
    }

    public int[] computePrimeFactorization(int numToFactorize) {
        if (numToFactorize < 2 || numToFactorize > this.maxNumToFactorize) {
            return null;
        }

        int remaining = numToFactorize;
        ArrayList<Integer> factors = new ArrayList<>();

        for (int prime : this.primes) {
            if (prime > remaining / prime) {
                break;
            }

            while (remaining % prime == 0) {
                factors.add(prime);
                remaining /= prime;
            }
        }

        if (remaining > 1) {
            factors.add(remaining);
        }

        int[] result = new int[factors.size()];
        for (int i = 0; i < factors.size(); i++) {
            result[i] = factors.get(i);
        }
        return result;
    }

    private static int[] buildPrimeList(int max) {
        if (max < 2) {
            return new int[0];
        }

        boolean[] isPrime = new boolean[max + 1];
        for (int i = 2; i <= max; i++) {
            isPrime[i] = true;
        }

        for (int p = 2; p <= max / p; p++) {
            if (isPrime[p]) {
                for (int multiple = p * p; multiple <= max; multiple += p) {
                    isPrime[multiple] = false;
                }
            }
        }

        int count = 0;
        for (int i = 2; i <= max; i++) {
            if (isPrime[i]) {
                count++;
            }
        }

        int[] primeList = new int[count];
        int idx = 0;
        for (int i = 2; i <= max; i++) {
            if (isPrime[i]) {
                primeList[idx++] = i;
            }
        }

        return primeList;
    }
}
